// Full drain pass in a single node to guarantee serial execution and true
// stop-on-429. Emitting multiple items to downstream HTTP nodes runs in parallel
// in n8n, which would break the FIFO cap-stop guarantee (see CAR-371 review).
//
// Behavior per entry (FIFO oldest first):
//   200  → remove from queue, emit a 'drained' summary item for Linear comment
//   429  → stop the pass; entry stays for next day
//   other error → increment retryCount; drop only after 3 retries, emit 'failed'
// Entries older than 7 days are expired at the top.

const staticData = $getWorkflowStaticData('global');
staticData.deferred_fires = staticData.deferred_fires || [];

const now = Date.now();
const sevenDays = 7 * 24 * 60 * 60 * 1000;
const MAX_RETRIES = 3;

// Expire sweep.
const expired = [];
const live = [];
for (const entry of staticData.deferred_fires) {
  if (now - (entry.deferredAt || 0) > sevenDays) expired.push(entry);
  else live.push(entry);
}
live.sort((a, b) => (a.deferredAt || 0) - (b.deferredAt || 0));
staticData.deferred_fires = live;

// Collected results for downstream Slack + Linear comment nodes.
const drained = [];
const failed = [];
let stoppedAtCap = false;

for (const entry of [...live]) {
  let resp;
  try {
    resp = await fetch(entry.routineUrl, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${entry.routineToken}`,
        'anthropic-beta': 'experimental-cc-routine-2026-04-01',
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ text: entry.firePayloadText }),
    });
  } catch (err) {
    // Network/DNS error — treat as transient, keep with retry count.
    entry.retryCount = (entry.retryCount || 0) + 1;
    if (entry.retryCount >= MAX_RETRIES) {
      failed.push({ ...entry, reason: 'network', error: String(err) });
      staticData.deferred_fires = staticData.deferred_fires.filter(e => e.issueId !== entry.issueId || e.deferredAt !== entry.deferredAt);
    }
    continue;
  }

  const status = resp.status;
  let body;
  try { body = await resp.json(); } catch { body = {}; }

  if (status >= 200 && status < 300) {
    // Success — remove from queue, record for Linear comment
    staticData.deferred_fires = staticData.deferred_fires.filter(e => e.issueId !== entry.issueId || e.deferredAt !== entry.deferredAt);
    drained.push({ ...entry, response: body });
  } else if (status === 429) {
    // Still at cap — stop processing; entry stays
    stoppedAtCap = true;
    break;
  } else {
    // Transient/other error — increment retry; drop after MAX_RETRIES
    entry.retryCount = (entry.retryCount || 0) + 1;
    if (entry.retryCount >= MAX_RETRIES) {
      failed.push({ ...entry, reason: `http_${status}`, response: body });
      staticData.deferred_fires = staticData.deferred_fires.filter(e => e.issueId !== entry.issueId || e.deferredAt !== entry.deferredAt);
    }
  }
}

return [{
  json: {
    drained,
    failed,
    expired,
    stoppedAtCap,
    remaining: (staticData.deferred_fires || []).length,
    ts: new Date().toISOString(),
  }
}];

// Emit one item per drained entry for Linear comment posting.
const drained = $input.first().json.drained || [];
if (drained.length === 0) return [{ json: { _skip: true } }];
return drained.map(d => ({ json: d }));

